  1→/**
  2→ * Project API Client
  3→ *
  4→ * TypeScript client for Project API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on projects.
  6→ */
  7→
  8→import type {
  9→  ProjectData,
 10→  ProjectListParams,
 11→  ProjectCreateInput,
 12→  ProjectUpdateInput,
 13→  ApiListResponse,
 14→  ApiResponse,
 15→  ApiClientConfig,
 16→} from './types';
 17→import { ApiClientError, parseApiError, parseJson } from './shared';
 18→
 19→export { ApiClientError } from './shared';
 20→
 21→/**
 22→ * Default base URL for API requests
 23→ */
 24→const DEFAULT_BASE_URL = '/api';
 25→
 26→/**
 27→ * Project API Client
 28→ *
 29→ * Provides typed methods for Project CRUD operations.
 30→ */
 31→export class ProjectApiClient {
 32→  private baseUrl: string;
 33→  private fetchFn: typeof globalThis.fetch;
 34→  private defaultHeaders: Record<string, string>;
 35→
 36→  constructor(config: ApiClientConfig = {}) {
 37→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 38→    this.fetchFn = config.fetch ?? fetch;
 39→    this.defaultHeaders = {
 40→      'Content-Type': 'application/json',
 41→      ...config.headers,
 42→    };
 43→  }
 44→
 45→  /**
 46→   * Build full URL for endpoint
 47→   */
 48→  private url(path: string, params?: Record<string, string | undefined>): string {
 49→    const fullUrl = `${this.baseUrl}${path}`;
 50→
 51→    if (params) {
 52→      const searchParams = new URLSearchParams();
 53→      for (const [key, value] of Object.entries(params)) {
 54→        if (value !== undefined) {
 55→          searchParams.append(key, value);
 56→        }
 57→      }
 58→      const queryString = searchParams.toString();
 59→      if (queryString) {
 60→        return `${fullUrl}?${queryString}`;
 61→      }
 62→    }
 63→
 64→    return fullUrl;
 65→  }
 66→
 67→  /**
 68→   * GET /api/projects
 69→   *
 70→   * List all projects with optional filtering.
 71→   */
 72→  async getProjects(params?: ProjectListParams): Promise<ApiListResponse<ProjectData>> {
 73→    const response = await this.fetchFn(
 74→      this.url('/projects', {
 75→        status: params?.status,
 76→        managerId: params?.managerId,
 77→        contactId: params?.contactId,
 78→        dealId: params?.dealId,
 79→        skip: params?.skip?.toString(),
 80→        take: params?.take?.toString(),
 81→      }),
 82→      {
 83→        headers: this.defaultHeaders,
 84→      }
 85→    );
 86→
 87→    if (!response.ok) {
 88→      return parseApiError(response);
 89→    }
 90→
 91→    return parseJson<ApiListResponse<ProjectData>>(response);
 92→  }
 93→
 94→  /**
 95→   * GET /api/projects/[id]
 96→   *
 97→   * Fetch a single project by ID.
 98→   */
 99→  async getProject(id: string): Promise<ApiResponse<ProjectData>> {
100→    if (!id) {
101→      throw new ApiClientError(400, 'Validation failed', 'id is required');
102→    }
103→
104→    const response = await this.fetchFn(this.url(`/projects/${id}`), {
105→      headers: this.defaultHeaders,
106→    });
107→
108→    if (!response.ok) {
109→      return parseApiError(response);
110→    }
111→
112→    return parseJson<ApiResponse<ProjectData>>(response);
113→  }
114→
115→  /**
116→   * POST /api/projects
117→   *
118→   * Create a new project.
119→   */
120→  async createProject(data: ProjectCreateInput): Promise<ApiResponse<ProjectData>> {
121→    const response = await this.fetchFn(this.url('/projects'), {
122→      method: 'POST',
123→      headers: this.defaultHeaders,
124→      body: JSON.stringify(data),
125→    });
126→
127→    if (!response.ok) {
128→      return parseApiError(response);
129→    }
130→
131→    return parseJson<ApiResponse<ProjectData>>(response);
132→  }
133→
134→  /**
135→   * PATCH /api/projects/[id]
136→   *
137→   * Update an existing project.
138→   */
139→  async updateProject(
140→    id: string,
141→    data: ProjectUpdateInput
142→  ): Promise<ApiResponse<ProjectData>> {
143→    if (!id) {
144→      throw new ApiClientError(400, 'Validation failed', 'id is required');
145→    }
146→
147→    const response = await this.fetchFn(this.url(`/projects/${id}`), {
148→      method: 'PATCH',
149→      headers: this.defaultHeaders,
150→      body: JSON.stringify(data),
151→    });
152→
153→    if (!response.ok) {
154→      return parseApiError(response);
155→    }
156→
157→    return parseJson<ApiResponse<ProjectData>>(response);
158→  }
159→
160→  /**
161→   * DELETE /api/projects/[id]
162→   *
163→   * Soft-delete a project.
164→   */
165→  async deleteProject(id: string): Promise<ApiResponse<ProjectData>> {
166→    if (!id) {
167→      throw new ApiClientError(400, 'Validation failed', 'id is required');
168→    }
169→
170→    const response = await this.fetchFn(this.url(`/projects/${id}`), {
171→      method: 'DELETE',
172→      headers: this.defaultHeaders,
173→    });
174→
175→    if (!response.ok) {
176→      return parseApiError(response);
177→    }
178→
179→    return parseJson<ApiResponse<ProjectData>>(response);
180→  }
181→}
182→
183→/**
184→ * Default singleton instance
185→ */
186→export const projectsApi = new ProjectApiClient();
187→
188→/**
189→ * Convenience exports
190→ */
191→export const {
192→  getProjects,
193→  getProject,
194→  createProject,
195→  updateProject,
196→  deleteProject,
197→} = projectsApi;
198→
199→export default projectsApi;
